### 11. **WebSocket Client Features**

For browser-based UIs:
```typescript
const client = createSessionClient({
  sessionId: "sess-123",
  token: "token_xyz", // Short-lived session token (not API key)
  url: "https://api.deus.co",
  reconnect: {
    enabled: true, // Auto-reconnect with exponential backoff
    maxRetries: Infinity,
    initialDelayMs: 1000,
    maxDelayMs: 30000,
    multiplier: 2,
    connectionTimeoutMs: 10000,
    minUptimeMs: 5000, // Prevent thrashing on rolling deploys
  },
});

// Subscribe to all state changes
client.subscribe((state) => {
  if (state.pendingQuestion) {
    client.answerQuestion(
      state.pendingQuestion.questionId,
      state.pendingQuestion.sessionId,
      ["yes"],
    );
  }
  if (state.pendingPermission) {
    client.respondToPermission(
      state.pendingPermission.requestId,
      state.pendingPermission.sessionId,
      { behavior: "allow" },
    );
  }
});

client.connect();
client.send("Fix the bug");
```

### 12. **Error Handling**

```typescript
import { run, isDeusError, DeusError } from "@deus-hq/sdk";

try {
  await run({ task: "Fix tests", repo: "github.com/acme/backend" });
} catch (err) {
  if (isDeusError(err)) {
    console.error(`[${err.code}] ${err.message}`);
    // err.code: "MISSING_API_KEY" | "API_ERROR" | "TIMEOUT" | "ABORTED" | "INVALID_RESPONSE"
    // err.statusCode: HTTP status if from API
    // err.requestId: X-Request-ID for debugging
  }
}

// During streaming, errors arrive as events:
for await (const event of stream(session, "Fix tests")) {
  if (event.type === "session.error") {
    console.error(event.error.message);
    if (!event.recoverable) break; // Unrecoverable error
  }
}
```

